const ids = String($env.GHL_LOCATION_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (ids.length === 0) throw new Error('GHL_LOCATION_IDS no configurado');
return ids.map(location_id => ({ json: { location_id } }));

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const stateRow    = $input.first().json;
const location_id = stateRow.location_id;
const lastSynced  = stateRow.last_synced_at;
const lastCursor  = stateRow.last_cursor;
const apiKey      = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let allConvs   = [];
let startAfter = lastCursor || null;
let page = 0;
const MAX_PAGES = 300;

while (page < MAX_PAGES) {
  const url = new URL('https://services.leadconnectorhq.com/conversations/search');
  url.searchParams.set('locationId', location_id);
  url.searchParams.set('limit', '100');
  if (lastSynced && !startAfter) url.searchParams.set('startAfterDate', lastSynced);
  if (startAfter) url.searchParams.set('startAfter', startAfter);

  let resp;
  let retries = 0;
  while (retries < 5) {
    try {
      resp = await fetch(url.toString(), {
        headers: { 'Authorization': 'Bearer ' + apiKey, 'Version': '2021-04-15' }
      });
      if (resp.status === 429) { await sleep(Math.pow(2, retries) * 1000); retries++; continue; }
      break;
    } catch (err) {
      if (retries >= 4) throw err;
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
    }
  }
  if (!resp.ok) throw new Error('GHL API error ' + resp.status + ' conversations page ' + page);

  const data  = await resp.json();
  const convs = data.conversations || [];
  allConvs = allConvs.concat(convs);

  startAfter = data.meta?.startAfter || null;
  if (!startAfter || convs.length === 0) break;
  page++;
  await sleep(130);
}

return [{ json: { location_id, conversations: allConvs, next_cursor: startAfter } }];

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
function cleanStr(val, maxLen) { if (!val) return null; const s = String(val).trim().substring(0, maxLen); return s.length > 0 ? s : null; }
function validateGHLId(val) { if (!val) return null; const s = String(val).trim(); return REGEX_GHL_ID.test(s) ? s : null; }
function parseISODate(val) { if (!val) return null; const ts = Date.parse(String(val)); return isNaN(ts) ? null : new Date(ts).toISOString(); }
function parseIntSafe(val) { if (val === null || val === undefined || val === '') return null; const n = parseInt(val, 10); return isNaN(n) ? null : n; }

const { location_id, conversations, next_cursor } = $input.first().json;

const cleaned = conversations
  .filter(c => REGEX_GHL_ID.test(String(c.id || '').trim()) && REGEX_LOCATION_ID.test(String(c.locationId || location_id || '').trim()))
  .map(c => ({
    conversation_id:     String(c.id).trim(),
    contact_id:          validateGHLId(c.contactId),
    location_id:         String(c.locationId || location_id).trim(),
    channel_type:        cleanStr(c.type || c.channelType, 30),
    inbox_id:            validateGHLId(c.inboxId),
    inbox_name:          cleanStr(c.inboxName, 200),
    assigned_user_id:    validateGHLId(c.userId || c.assignedUserId),
    assigned_user_name:  cleanStr(c.userName || c.assignedUserName, 200),
    status:              cleanStr(c.status, 20),
    unread_count:        parseIntSafe(c.unreadCount) || 0,
    last_message_at:     parseISODate(c.lastMessageDate || c.lastMessageAt),
    ghl_created_at:      parseISODate(c.dateAdded || c.createdAt),
    synced_at:           new Date().toISOString()
  }))
  .filter(c => c.contact_id);

return [{ json: { location_id, conversations: cleaned, next_cursor, total: cleaned.length } }];

// Para cada conversación sin first_inbound_body, llama a la API de mensajes
// y extrae el primer mensaje inbound (más antiguo).
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const rows   = Array.isArray($input.all()) ? $input.all().map(i => i.json) : [];
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

const results = [];

for (const row of rows) {
  const convId = row.conversation_id;
  if (!convId) continue;

  try {
    // GHL devuelve mensajes en orden descendente (más reciente primero).
    // Pedimos los últimos 100 mensajes y luego paginamos hacia atrás
    // para llegar al primer inbound. Máximo 5 páginas para no abusar.
    let firstInbound = null;
    let lastMsgId    = null;
    let pagina       = 0;
    const MAX_PAG    = 5;

    while (pagina < MAX_PAG) {
      const url = new URL(`https://services.leadconnectorhq.com/conversations/${convId}/messages`);
      url.searchParams.set('limit', '100');
      if (lastMsgId) url.searchParams.set('lastMessageId', lastMsgId);

      let resp;
      let retries = 0;
      while (retries < 3) {
        try {
          resp = await fetch(url.toString(), {
            headers: { 'Authorization': 'Bearer ' + apiKey, 'Version': '2021-04-15' }
          });
          if (resp.status === 429) { await sleep(Math.pow(2, retries) * 1000); retries++; continue; }
          break;
        } catch (err) {
          if (retries >= 2) throw err;
          await sleep(Math.pow(2, retries) * 1000);
          retries++;
        }
      }
      if (!resp || !resp.ok) break;

      const data = await resp.json();
      const msgs = (data.messages?.messages || data.messages || []);
      if (!Array.isArray(msgs) || msgs.length === 0) break;

      // Filtra inbound y quédate con los que tienen cuerpo de texto
      const inbounds = msgs.filter(m =>
        String(m.direction || m.messageDirection || '').toLowerCase() === 'inbound' &&
        m.body && String(m.body).trim().length > 0
      );

      // Los mensajes vienen de más reciente a más antiguo.
      // El más antiguo de esta página es el candidato a primer mensaje.
      if (inbounds.length > 0) {
        // Tomamos el último de los inbound en esta página (más antiguo de la página)
        const candidate = inbounds[inbounds.length - 1];
        if (!firstInbound) {
          firstInbound = candidate;
        } else {
          // Comparar timestamps para quedarse con el más antiguo
          const ts1 = Date.parse(firstInbound.dateAdded || firstInbound.createdAt || '');
          const ts2 = Date.parse(candidate.dateAdded || candidate.createdAt || '');
          if (!isNaN(ts2) && (isNaN(ts1) || ts2 < ts1)) firstInbound = candidate;
        }
      }

      const hasMore = data.messages?.nextPage === true;
      if (!hasMore) break;
      lastMsgId = data.messages?.lastMessageId || msgs[msgs.length - 1]?.id || null;
      if (!lastMsgId) break;
      pagina++;
      await sleep(150);
    }

    if (firstInbound) {
      const body     = String(firstInbound.body).trim().substring(0, 65535);
      const sentAt   = firstInbound.dateAdded || firstInbound.createdAt || null;
      results.push({ json: { conversation_id: convId, first_inbound_body: body, first_inbound_at: sentAt } });
    }
  } catch (err) {
    // Continuar con la siguiente conversación ante errores individuales
    console.error('Error fetching messages for ' + convId + ': ' + err.message);
  }

  await sleep(150);
}

if (results.length === 0) return [{ json: { skipped: true } }];
return results;
